public class Solution {
    static class FenwickTree {
        private int size;
        private int[] tree;

        public FenwickTree(int size) {
            this.size = size;
            this.tree = new int[size + 1]; // 1-based indexing
        }

        public void update(int index, int delta) {
            index += 1; // convert to 1-based
            while (index <= size) {
                tree[index] += delta;
                index += index & -index;
            }
        }

        public int query(int index) {
            index += 1; // convert to 1-based
            int res = 0;
            while (index > 0) {
                res += tree[index];
                index -= index & -index;
            }
            return res;
        }

        public int rangeQuery(int l, int r) {
            return query(r) - query(l - 1);
        }
    }

    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int maxDepth = 5;
        FenwickTree[] ft = new FenwickTree[maxDepth + 1];
        for (int d = 0; d <= maxDepth; d++) {
            ft[d] = new FenwickTree(n);
        }

        // Precompute the depths for each number
        int[] depths = new int[n];
        for (int i = 0; i < n; i++) {
            depths[i] = computeDepth(nums[i]);
        }

        // Initialize the Fenwick Trees
        for (int i = 0; i < n; i++) {
            int d = depths[i];
            if (d <= maxDepth) {
                ft[d].update(i, 1);
            }
        }

        // Process queries
        long[] answer = new long[queries.length];
        int idx = 0;
        for (long[] q : queries) {
            if (q[0] == 1) {
