                }

                // Compute new depth
                int newD = computeDepth(newVal);
                if (newD <= maxDepth) {
                    ft[newD].update(pos, 1);
                }
            }
        }

        return answer;
    }

    public static int computeDepth(long x) {
        int depth = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            depth++;
        }
