                int r = (int) q[2];
                int k = (int) q[3];
                if (k > maxDepth) {
                    answer[idx++] = 0;
                    continue;
                }
                answer[idx++] = ft[k].rangeQuery(l, r);
            } else {
                // Type 2 query: [2, idx, val]
                int pos = (int) q[1];
                long oldVal = nums[pos];
                long newVal = q[2];
                nums[pos] = newVal;

                // Compute old depth
                int oldD = depths[pos];
                if (oldD <= maxDepth) {
                    ft[oldD].update(pos, -1);
                }

                // Compute new depth
                int newD = computeDepth(newVal);
                if (newD <= maxDepth) {
                    ft[newD].update(pos, 1);
                }
            }
        }

        return answer;
    }

    public static int computeDepth(long x) {
        int depth = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            depth++;
        }
        return depth;
    }
